mapper.insert:
INSERT INTO member_recharge_request (
    request_no, user_id, amount, status, screenshot_path, payer_remark
) VALUES (
    #{requestNo}, #{userId}, #{amount}, #{status}, #{screenshotPath}, #{payerRemark}
)

mapper.select:
SELECT 
FROM member_recharge_request rr
INNER JOIN member_user u ON u.id = rr.user_id
LEFT JOIN admin_user a ON a.id = rr.reviewed_by
WHERE rr.user_id = #{userId}

    AND (
        rr.created_at < #{cursorCreatedAt}
        OR (rr.created_at = #{cursorCreatedAt} AND rr.id < #{cursorId})
    )

ORDER BY rr.created_at DESC, rr.id DESC
LIMIT #{limit}

SELECT 
FROM member_recharge_request rr
INNER JOIN member_user u ON u.id = rr.user_id
LEFT JOIN admin_user a ON a.id = rr.reviewed_by
WHERE 1 = 1

    AND rr.status = #{status}


    AND (
        u.username LIKE CONCAT(#{userKeyword}, '%')
        OR u.mail LIKE CONCAT(#{userKeyword}, '%')
    )


    AND (
        rr.created_at < #{cursorCreatedAt}
        OR (rr.created_at = #{cursorCreatedAt} AND rr.id < #{cursorId})
    )

ORDER BY rr.created_at DESC, rr.id DESC
LIMIT #{limit}

mapper.update:
UPDATE member_recharge_request
SET status = 'REJECTED',
    reviewed_by = #{reviewedBy},
    reviewed_at = NOW(),
    reject_reason = #{reason}
WHERE id = #{id}
